INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los principios de libertad, capacidad y solidaridad económica informan todo el ordenamiento jurídico tributario.', '2003-12-17', '0f6150090fa2501c2f371f54c9882201' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '1';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'La actuación de la Administración tributaria se regirá por los principios de eficacia, proporcionalidad, celeridad e imparcialidad.', '2003-12-17', '17ceac5561290ef648a3bd78355620c0' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '2';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Las normas tributarias se interpretarán de acuerdo con las reglas establecidas en los artículos 3 y 4 del Código Civil.', '2003-12-17', 'ae956c4e7021c0cd186aa41052ce66a7' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '3';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Las obligaciones tributarias principales y accesorias se establecen en esta ley y en las normas tributarias especiales.', '2003-12-17', '45473e14e03ef7e7d5f9ac727d0794d6' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '5';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los sujetos pasivos son quienes realizan los hechos imponibles previstos en las normas tributarias.', '2003-12-17', 'ec30e8f63330546ecfe36d3876e6f6a5' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '10';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'El hecho imponible es la conducta descrita por la norma tributaria como presupuesto del tributo.', '2003-12-17', 'dd1a191deb3dc9f4787d07530157947b' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '12';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'La liquidación tributaria es el acto mediante el cual se determina la deuda tributaria.', '2003-12-17', 'ba1cd4aabe3a3d94cc986f27cab04d42' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '17';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los derechos de la Administración para determinar las deudas tributarias prescriben en cuatro años.', '2003-12-17', '8f82abe7fa5eda91569eb9f10c3a2515' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '21';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Las infracciones tributarias serán sancionadas conforme a lo dispuesto en esta ley.', '2003-12-17', '6c60b9e61ac2f850c82887733f38c337' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '26';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Responderán del pago de las deudas tributarias los terceros previstos en esta ley.', '2003-12-17', '49c3b8c9f79b75ca6aa52cd55f0bdb4c' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LGT' AND a.numero = '30';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los residentes fiscales en España tributarán por sus rentas mundiales. Los no residentes tributarán solo por rentas obtenidas en España.', '2006-12-28', 'ec3f3c933968d605fcd843a6b67db0af' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '1';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Son sujetos pasivos los residentes y no residentes que obtengan rentas en territorio español.', '2006-12-28', '261b29f2bdf9f4e81e6d23e74671e65c' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '2';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Son rendimientos del trabajo las contraprestaciones obtenidas por servicios laborales por cuenta ajena.', '2006-12-28', '6211ad75600c09685d79a42209217623' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '3';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Son rendimientos de actividades económicas los obtenidos por el ejercicio directo, profesional o empresarial.', '2006-12-28', '1ca9472bf2cb14eed9b2149be121fdbf' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '4';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Son rendimientos del capital mobiliario los obtenidos por participaciones en entidades y créditos.', '2006-12-28', 'd64534740442b0a6f8d0cc56b31136a7' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '5';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Son ganancias patrimoniales el aumento o disminución del patrimonio obtenido por transmisión o no.', '2006-12-28', 'e424a70cb7f89d3dffcf001a9760a9c6' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '6';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Las deducciones en la cuota se aplicarán sobre el resultado de la declaración.', '2006-12-28', '2b2bed9a6e41c0ac097107d860dad662' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '8';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Las retenciones e ingresos a cuenta se practicarán sobre los rendimientos previstos en esta ley.', '2006-12-28', '8b0cd05720578113703c76aae8a17f4f' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '10';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los contribuyentes que obtengan rendimientos del trabajo sujetos a retención presentarán declaración anual.', '2006-12-28', 'f51de9b6dd7513f174e3663a6ec9f4b8' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '16';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los contribuyentes que ejerzan actividades económicas realizarán pagos fraccionados trimestrales.', '2006-12-28', 'ae94606b708ffb040fc170e85b26105f' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIRPF' AND a.numero = '19';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'El hecho imponible del IVA consiste en la entrega de bienes y prestación de servicios en territorio español.', '1992-12-28', '5b4d385c41ab1d7d07c6c6fed9b477b0' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '1';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Son sujetos pasivos los empresarios o profesionales que realicen entregas o prestaciones.', '1992-12-28', '91b43ae7bfe27c1240c6b6e07f51e612' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '2';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Se entiende por bienes todas las cosas corporales y por servicios todas las prestaciones.', '1992-12-28', 'c2fecfe028025b07243d338c2c3904db' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '3';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'No estarán sujetas al IVA las entregas de bienes y prestaciones de servicios exentas.', '1992-12-28', '7f3eaf6c5bba6814b8775063ff930ecd' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '6';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'El tipo de gravamen general será del 21%. Podrán establecerse tipos reducidos.', '1992-12-28', '93a85326d72e630b80d16244ef1426ad' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '8';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'La cuota soportada es la IVA repercutida por el transmitente o prestador.', '1992-12-28', 'd434bde80973fa34a94090918bae5d6c' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '10';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Los sujetos pasivos practicarán autoliquidaciones trimestrales o mensuales.', '1992-12-28', '7d624dcd9f9fab491d7da1f5ed861645' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '12';
INSERT INTO version_articulo (articulo_id, texto, vigente_desde, content_hash) SELECT a.id, 'Las entregas de bienes y prestaciones de servicios se documentarán mediante facturas.', '1992-12-28', 'cd007be5c656966b6ebf512232307f31' FROM articulo a JOIN norma n ON n.id = a.norma_id WHERE n.codigo = 'LIVA' AND a.numero = '15';
